/**
 * Returns a borrowed pointer to the operation handle that produced this
 * completion. Lifetime = until [`cosmos_completion_free`].
 */
const struct cosmos_operation_handle_t *cosmos_completion_op_handle(const struct cosmos_completion_t *c);

/**
 * Coarse status code (always populated even when rich detail is suppressed).
 */
cosmos_error_code_t cosmos_completion_status(const struct cosmos_completion_t *c);

/**
 * True iff `cosmos_operation_handle_cancel` was observed on the producing
 * handle before the completion was posted.
 */
bool cosmos_completion_was_cancel_requested(const struct cosmos_completion_t *c);

/**
 * Fills `out_view` with a snapshot of the completion's scalar fields and
 * returns `SUCCESS`. Returns `INVALID_ARGUMENT` (leaving `*out_view`
 * untouched) when `c` or `out_view` is NULL.
 *
 * This is the single-call alternative to `cosmos_completion_outcome` +
 * `_status` + `_user_data` + `_was_cancel_requested`.
 */
cosmos_error_code_t cosmos_completion_view(const struct cosmos_completion_t *c,
                                           struct cosmos_completion_view_t *out_view);

/**
 * Takes ownership of the response delivered by an `Ok` completion.
 * Returns NULL on `Error` / `Cancelled` completions, on NULL input,
 * and on every subsequent call after the first successful take.
 *
 * Caller must free the returned handle via `cosmos_response_free`.
 */
struct cosmos_response_t *cosmos_completion_take_response(struct cosmos_completion_t *c);

/**
 * Borrowed access to the response payload. Returns NULL when the
 * completion outcome is not `Ok`, when no response was attached, or
 * after `_take_response` already moved ownership out.
 *
 * Lifetime: until the next `_take_response` call or until the
 * completion itself is freed.
 */
const struct cosmos_response_t *cosmos_completion_response(const struct cosmos_completion_t *c);

/**
 * Take ownership of the rich error payload. Returns NULL when
 * `outcome != Error`, when the queue was created with
 * `include_error_details = false`, or after a previous `_take_error` call.
 */
struct cosmos_error_t *cosmos_completion_take_error(struct cosmos_completion_t *c);

/**
 * Borrowed access to the rich error payload. NULL on `Ok` / `Cancelled`,
 * when details are suppressed, or after a previous `_take_error` call.
 */
const struct cosmos_error_t *cosmos_completion_error(const struct cosmos_completion_t *c);

/**
 * Free a completion record. Any pointer obtained via
 * [`cosmos_completion_error`] (borrowed) becomes invalid; ownership obtained
 * via [`cosmos_completion_take_error`] remains valid until that handle's
 * own `_free` call.
 */
void cosmos_completion_free(struct cosmos_completion_t *c);

/**
 * Request cooperative cancellation. Idempotent and non-blocking.
 *
 * Sets the cancel-requested flag and wakes the submit task's
 * `tokio::select!` cancel branch (via a stored `Notify` permit, so a cancel
 * that races ahead of the task is still observed). The task then drops the
 * in-flight driver future and posts a `CANCELLED` completion. If the
 * operation already produced a completion before the cancel was observed,
 * the cancel is a no-op for the outcome but is still reflected in
 * `cosmos_completion_was_cancel_requested`.
 */
void cosmos_operation_handle_cancel(struct cosmos_operation_handle_t *op);

/**
 * Poll the operation's lifecycle state. Returns `InFlight` if `op` is NULL.
 */
cosmos_operation_handle_state_t cosmos_operation_handle_state(const struct cosmos_operation_handle_t *op);

/**
 * Free the FFI handle. Does NOT cancel the operation ŌĆö call
 * `cosmos_operation_handle_cancel` first if needed. NULL is a no-op.
 *
 * Drops this handle's `Arc` reference. If the completion record still holds
 * its own reference, the inner operation state stays alive.
 */
void cosmos_operation_handle_free(struct cosmos_operation_handle_t *op);

/**
 * Clones an existing container-reference handle into a fresh FFI
 * handle that shares the underlying state.
 */
int32_t cosmos_container_ref_clone(const struct cosmos_container_ref_t *container,
                                   struct cosmos_container_ref_t **out_clone);

/**
 * Frees a container-reference handle. NULL is a no-op.
 */
void cosmos_container_ref_free(struct cosmos_container_ref_t *container);

/**
 * Synchronously resolves a container reference. Bridges
 * [`azure_data_cosmos_driver::driver::CosmosDriver::resolve_container_by_name`]
 * through the wrapper's Tokio runtime via `block_on`.
 *
 * Touches the network on cache miss (reads container metadata from
 * the gateway). On cache hit returns immediately without I/O.
 *
 * # Parameters
 *
 * - `runtime` ŌĆö non-NULL.
 * - `driver` ŌĆö non-NULL; the driver whose container cache to consult.
 * - `database_id` ŌĆö NUL-terminated UTF-8.
 * - `container_id` ŌĆö NUL-terminated UTF-8.
 * - `out_container` ŌĆö non-NULL slot for the resolved handle.
 * - `out_error` ŌĆö optional rich error on failure. NULL silently drops.
 *
 * # Returns
 *
 * `SUCCESS` (0) on success, the standard coarse codes on failure
 * derived from the driver-side error.
 */
int32_t cosmos_driver_resolve_container_blocking(const struct cosmos_runtime_t *runtime,
                                                 const struct cosmos_driver_t *driver,
                                                 const char *database_id,
                                                 const char *container_id,
                                                 struct cosmos_container_ref_t **out_container,
                                                 struct cosmos_error_t **out_error);

/**
 * Creates a name-based database reference parented to `account`.
 *
 * Mirrors `DatabaseReference::from_name`. Pure value-type construction;
 * never touches the network. The supplied `account` is cloned into the
 * new database reference, so freeing `account` after this call does not
 * invalidate the database handle.
 *
 * # Parameters
 *
 * - `account` ŌĆö parent account reference. Must be non-NULL.
 * - `database_id` ŌĆö NUL-terminated UTF-8 database name. Must be
 *   non-NULL.
 * - `out_database` ŌĆö receives the new FFI handle on success. Must be
 *   non-NULL.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_database` populated.
 * - `INVALID_ARGUMENT` (1) when `account`, `database_id`, or
 *   `out_database` is NULL.
 * - `INVALID_UTF8` (2) when `database_id` is not valid UTF-8.
 */
int32_t cosmos_database_ref_create(const struct cosmos_account_ref_t *account,
                                   const char *database_id,
                                   struct cosmos_database_ref_t **out_database);

/**
 * Clones an existing database reference into a fresh FFI handle that
 * shares the underlying state.
 *
 * Cheap ŌĆö an atomic refcount bump on a single `Arc`.
 */
int32_t cosmos_database_ref_clone(const struct cosmos_database_ref_t *database,
                                  struct cosmos_database_ref_t **out_clone);

/**
 * Frees a database-reference handle. NULL is a no-op.
 */
void cosmos_database_ref_free(struct cosmos_database_ref_t *database);

/**
 * Frees a driver handle. Drops the FFI-side `Arc` reference; the
 * underlying driver remains alive in the runtime's cache until the
 * owning `cosmos_runtime_t` is freed (spec section 4.4.1). NULL is a no-op.
 */
void cosmos_driver_free(struct cosmos_driver_t *driver);

/**
 * Synchronously gets or creates the driver for the supplied account.
 *
 * Bridges
 * `CosmosDriverRuntime::get_or_create_driver` through the wrapper's
 * own multi-threaded Tokio runtime via `block_on`. Suitable for
 * startup-time initialization; for runtime use prefer the async
 * `_submit` variant.
 *
 * # Cache behavior (spec section 4.4.1)
 *
 * - The runtime caches drivers by endpoint URL. A second call with the
 *   same endpoint returns the cached driver and **silently ignores**
 *   `options`.
 * - Two `AccountReference`s with the same endpoint but different
 *   credentials collide in the cache ŌĆö first credential wins.
 * - Cache eviction happens only when the owning `cosmos_runtime_t` is
 *   freed; freeing a `cosmos_driver_t` does not evict.
 *
 * The `5001` `OPTIONS_IGNORED_ON_CACHE_HIT` advisory described in spec
 * Section 4.4.1 is not emitted today ŌĆö see the module-level
 * `Cache-hit advisory` note for the rationale.
 *
 * # Parameters
 *
 * - `runtime` ŌĆö non-NULL runtime handle.
 * - `account` ŌĆö non-NULL account reference.
 * - `options` ŌĆö optional driver options. NULL means "use the driver's
 *   defaults" (matches passing `None` to the underlying API).
 * - `out_driver` ŌĆö non-NULL slot that receives the new driver handle
 *   on success.
 * - `out_error` ŌĆö optional. Receives a rich `cosmos_error_t *` on
 *   driver-side failure (e.g. network errors during
 *   `CosmosDriver::initialize`). NULL silently drops it.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_driver` populated.
 * - `INVALID_ARGUMENT` (1) when `runtime`, `account`, or `out_driver`
 *   is NULL.
 * - One of the `2xxx` / `3xxx` codes derived from the driver-side
 *   error per spec section 3.5.1 when the underlying
 *   `get_or_create_driver` returns an error.
 */
int32_t cosmos_driver_get_or_create_blocking(const struct cosmos_runtime_t *runtime,
                                             const struct cosmos_account_ref_t *account,
                                             const struct cosmos_driver_options_t *options,
                                             struct cosmos_driver_t **out_driver,
                                             struct cosmos_error_t **out_error);

/**
 * Frees a built `cosmos_driver_options_t *`. NULL is a no-op.
 */
void cosmos_driver_options_free(struct cosmos_driver_options_t *options);

/**
 * Allocates a new builder bound to the supplied account reference.
 *
 * The account is cloned into the builder, so freeing `account` after
 * this call does not invalidate the builder. Returns NULL if `account`
 * is NULL.
 */
struct cosmos_driver_options_builder_t *cosmos_driver_options_builder_new(const struct cosmos_account_ref_t *account);

/**
 * Frees a builder that was never consumed by `_build`. NULL is a no-op.
 */
void cosmos_driver_options_builder_free(struct cosmos_driver_options_builder_t *builder);

int32_t cosmos_driver_options_builder_with_preferred_regions(struct cosmos_driver_options_builder_t *builder,
                                                             const char *const *regions,
                                                             uintptr_t regions_len);

/**
 * Sets the per-driver default operation options.
 *
 * Mirrors [`DriverOptionsBuilder::with_operation_options`]. The supplied
 * flat `cosmos_operation_options_t` (see
 * [`crate::op_request::CosmosOperationOptions`]) is converted and **cloned**
 * into the builder; the caller retains ownership of the source struct. NULL
 * `options` is rejected with `INVALID_ARGUMENT` ŌĆö pass a struct from
 * [`crate::op_request::cosmos_operation_options_default`] (mutated as
 * needed) or don't call this setter at all to inherit the driver defaults.
 * An out-of-range option value is rejected with `INVALID_OPTION_VALUE`.
 */
int32_t cosmos_driver_options_builder_with_operation_options(struct cosmos_driver_options_builder_t *builder,
                                                             const struct cosmos_operation_options_t *options);

/**
 * Consumes the builder and returns a fresh `cosmos_driver_options_t *`.
 *
 * # Lifetime
 *
 * `_build` consumes the builder regardless of success or failure.
 * Callers must NOT call [`cosmos_driver_options_builder_free`] on the
 * same pointer afterwards.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_options` populated.
 * - `INVALID_ARGUMENT` (1) when `builder` or `out_options` is NULL. In
 *   the NULL-`out_options` case the builder is still consumed to avoid
 *   leaking the inner allocation.
 */
int32_t cosmos_driver_options_builder_build(struct cosmos_driver_options_builder_t *builder,
                                            struct cosmos_driver_options_t **out_options);

/**
 * Returns an all-unset [`CosmosDriverOptionsConfig`] by value. The host
 * mutates the fields it cares about and leaves the rest at their default
 * sentinels.
 */
struct cosmos_driver_options_config_t cosmos_driver_options_config_default(void);

/**
 * Builds a `cosmos_driver_options_t *` from an account reference and a flat
 * [`CosmosDriverOptionsConfig`] in a single call ŌĆö the single-call
 * alternative to `cosmos_driver_options_builder_new` + the per-field setters +
 * `cosmos_driver_options_builder_build`.
 *
 * # Parameters
 *
 * - `account` ŌĆö non-NULL account reference. Cloned into the options, so
 *   freeing `account` afterwards does not invalidate the result.
 * - `config` ŌĆö the flat config. A NULL pointer means "no preferred regions,
 *   default operation options" (equivalent to
 *   [`cosmos_driver_options_config_default`]).
 * - `out_options` ŌĆö on success, receives the new options handle. Must be
 *   non-NULL.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_options` populated.
 * - `INVALID_ARGUMENT` (1) when `account` or `out_options` is NULL, or a
 *   region entry is NULL.
 * - `INVALID_UTF8` (2) when a region name is not valid UTF-8.
 * - `INVALID_OPTION_VALUE` (4014) when an operation-option value is out of
 *   range.
 */
int32_t cosmos_driver_options_build(const struct cosmos_account_ref_t *account,
                                    const struct cosmos_driver_options_config_t *config,
                                    struct cosmos_driver_options_t **out_options);

/**
 * HTTP status code (always populated, including for synthetic errors).
 */
uint16_t cosmos_error_status_code(const struct cosmos_error_t *e);

/**
 * Sub-status code. Returns -1 when absent. Driver-side `SubStatusCode` is
 * `u16`; widening to `i32` lets us reserve -1 for "no sub-status" without
 * clipping any real value.
 */
int32_t cosmos_error_sub_status(const struct cosmos_error_t *e);

/**
 * True iff the error originated from a service wire response. Mirrors
 * `CosmosError::is_from_wire`.
 */
bool cosmos_error_is_from_wire(const struct cosmos_error_t *e);

/**
 * Borrowed message string. Returns NULL only when `e` is NULL.
 *
 * Lifetime = until [`cosmos_error_free`].
 */
const char *cosmos_error_message(const struct cosmos_error_t *e);

/**
 * Borrowed activity id from the wire response headers (or NULL when there
 * is no wire response or no activity id was present).
 */
const char *cosmos_error_activity_id(const struct cosmos_error_t *e);

/**
 * Borrowed session token from the wire response headers (or NULL).
 */
const char *cosmos_error_session_token(const struct cosmos_error_t *e);

/**
 * Borrowed ETag from the wire response headers (or NULL).
 */
const char *cosmos_error_etag(const struct cosmos_error_t *e);

/**
 * Retry-after duration in milliseconds, or -1 when absent / no wire response.
 */
int64_t cosmos_error_retry_after_ms(const struct cosmos_error_t *e);

/**
 * Borrowed backtrace string (rate-limited per
 * [`cosmos_set_backtrace_options`]).
 * Returns NULL when no backtrace was captured.
 */
const char *cosmos_error_backtrace(const struct cosmos_error_t *e);

/**
 * Fills `out_view` with a snapshot of the error's scalar and borrowed-string
 * fields and returns `SUCCESS`. Returns `INVALID_ARGUMENT` (leaving
 * `*out_view` untouched) when `e` or `out_view` is NULL.
 *
 * This is the single-call alternative to `cosmos_error_status_code` +
 * `_sub_status` + `_is_from_wire` + `_message` + `_activity_id` +
 * `_session_token` + `_etag` + `_retry_after_ms` + `_backtrace`. Every borrowed
 * pointer it returns is valid until [`cosmos_error_free`].
 */
cosmos_error_code_t cosmos_error_view(const struct cosmos_error_t *e,
                                      struct cosmos_error_view_t *out_view);

/**
 * Free a `cosmos_error_t *` obtained via `cosmos_completion_take_error` or
 * a synchronous `out_error` slot. NULL is a no-op. Calling on a borrowed
 * pointer (e.g. `cosmos_completion_error` result) is undefined behavior.
 */
void cosmos_error_free(struct cosmos_error_t *e);

/**
 * Sets process-global backtrace capture / resolution rate limits.
 *
 * Last-writer-wins across concurrent calls. Pass `0` to either parameter to
 * disable that knob. Environment-derived defaults (`RUST_LIB_BACKTRACE`,
 * `RUST_BACKTRACE`, `AZURE_COSMOS_BACKTRACE_*`) are overridden for the rest
 * of the process once this is called. See spec section 6.4.
 */
void cosmos_set_backtrace_options(uint32_t max_captures_per_second,
                                  uint32_t max_resolutions_per_second);

/**
 * Constructs a feed range covering the entire EPK key space. Mirrors
 * [`azure_data_cosmos_driver::models::FeedRange::full`].
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_fr` populated.
 * - `INVALID_ARGUMENT` (1) when `out_fr` is NULL.
 */
int32_t cosmos_feed_range_full(struct cosmos_feed_range_t **out_fr);

/**
 * Constructs a feed range that targets a single logical partition
 * key. Mirrors `FeedRange::for_partition(pk, container.partition_key_definition())`.
 *
 * The partition-key definition is extracted from `container`, so
 * callers do not have to plumb it manually.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_fr` populated.
 * - `INVALID_ARGUMENT` (1) when any pointer is NULL.
 */
int32_t cosmos_feed_range_for_partition_key(const struct cosmos_container_ref_t *container,
                                            const struct cosmos_partition_key_t *pk,
                                            struct cosmos_feed_range_t **out_fr);

/**
 * Clones an existing feed-range handle. Cheap atomic refcount bump.
 */
int32_t cosmos_feed_range_clone(const struct cosmos_feed_range_t *fr,
                                struct cosmos_feed_range_t **out_clone);

/**
 * Frees a feed-range handle. NULL is a no-op.
 */
void cosmos_feed_range_free(struct cosmos_feed_range_t *fr);

/**
 * Returns an all-unset [`CosmosOperationOptions`] by value. The host
 * mutates the fields it cares about and leaves the rest at their inherit
 * sentinels.
 */
struct cosmos_operation_options_t cosmos_operation_options_default(void);

/**
 * Allocates a new partition-key builder. Always succeeds; the returned
 * handle holds an empty component list.
 */
struct cosmos_partition_key_builder_t *cosmos_partition_key_builder_new(void);

/**
 * Frees a builder that was never consumed by [`cosmos_partition_key_builder_build`].
 * NULL is a no-op.
 */
void cosmos_partition_key_builder_free(struct cosmos_partition_key_builder_t *builder);

/**
 * Appends a string component to the partition key.
 */
int32_t cosmos_partition_key_builder_add_string(struct cosmos_partition_key_builder_t *builder,
                                                const char *value);

/**
 * Appends a numeric component to the partition key. Rejects NaN and
 * ┬▒Ōł× with `INVALID_OPTION_VALUE`.
 */
int32_t cosmos_partition_key_builder_add_number(struct cosmos_partition_key_builder_t *builder,
                                                double value);

/**
 * Appends a boolean component to the partition key.
 *
 * `value` is a C boolean (`0` = false, non-zero = true). It is taken as a
 * `u8` rather than a Rust `bool` so an arbitrary host-supplied byte cannot
 * produce an invalid `bool` (which would be undefined behavior).
 */
int32_t cosmos_partition_key_builder_add_bool(struct cosmos_partition_key_builder_t *builder,
                                              uint8_t value);

/**
 * Appends an explicit `null` component to the partition key.
 */
int32_t cosmos_partition_key_builder_add_null(struct cosmos_partition_key_builder_t *builder);

/**
 * Appends an `undefined` (missing-value) component to the partition
 * key.
 */
int32_t cosmos_partition_key_builder_add_undefined(struct cosmos_partition_key_builder_t *builder);

/**
 * Consumes the builder and returns an immutable
 * `cosmos_partition_key_t *`.
 *
 * # Lifetime
 *
 * `_build` consumes the builder regardless of success or failure.
 * Callers must NOT call [`cosmos_partition_key_builder_free`] on the
 * same pointer afterwards.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_pk` populated.
 * - `INVALID_ARGUMENT` (1) when `builder` or `out_pk` is NULL. In
 *   the NULL-`out_pk` case the builder is still consumed to avoid
 *   leaking the inner allocation.
 * - `INVALID_PARTITION_KEY` (4004) when no components were added.
 *   The driver's `EMPTY` partition key has a specific meaning
 *   (cross-partition fan-out) and host SDKs cannot construct it via
 *   the builder by accident; if you need it explicitly, use
 *   `cosmos_partition_key_empty`.
 */
int32_t cosmos_partition_key_builder_build(struct cosmos_partition_key_builder_t *builder,
                                           struct cosmos_partition_key_t **out_pk);

/**
 * Returns a fresh handle for the special cross-partition / "empty"
 * partition key (driver constant
 * `azure_data_cosmos_driver::models::PartitionKey::EMPTY`).
 *
 * This is the only way to obtain an empty key through the FFI ŌĆö the
 * builder rejects empty-build with `INVALID_PARTITION_KEY` to catch
 * accidental misuse.
 */
struct cosmos_partition_key_t *cosmos_partition_key_empty(void);

/**
 * Clones an existing partition-key handle. Cheap ŌĆö an atomic refcount
 * bump on a single `Arc`.
 */
int32_t cosmos_partition_key_clone(const struct cosmos_partition_key_t *pk,
                                   struct cosmos_partition_key_t **out_clone);

/**
 * Frees a partition-key handle. NULL is a no-op.
 */
void cosmos_partition_key_free(struct cosmos_partition_key_t *pk);

/**
 * Returns the number of components in this partition key.
 *
 * Returns `0` for NULL (matches the driver's `EMPTY` semantics, but
 * also serves as a safe default for callers that pass a freed or
 * uninitialized pointer ŌĆö distinguish from a genuinely-empty key by
 * checking for NULL up-front).
 */
uintptr_t cosmos_partition_key_component_count(const struct cosmos_partition_key_t *pk);

/**
 * Returns `true` when this partition key has zero components.
 *
 * Returns `true` for NULL (a NULL handle has no components by
 * definition; the contract mirrors `cosmos_partition_key_component_count`
 * returning `0`).
 */
bool cosmos_partition_key_is_empty(const struct cosmos_partition_key_t *pk);

/**
 * Frees a response handle. NULL is a no-op.
 */
void cosmos_response_free(struct cosmos_response_t *response);

/**
 * Returns the HTTP status code from the response (e.g. 200, 201,
 * 204). Returns `0` for NULL / degenerate responses.
 */
uint16_t cosmos_response_status_code(const struct cosmos_response_t *response);

/**
 * Returns the request charge in Request Units, or `0.0` when the
 * header is absent / response is NULL / response is degenerate.
 */
double cosmos_response_request_charge(const struct cosmos_response_t *response);

/**
 * Borrowed pointer to the activity id, or NULL when absent / response
 * is NULL.
 */
const char *cosmos_response_activity_id(const struct cosmos_response_t *response);

/**
 * Borrowed pointer to the session token, or NULL when absent.
 */
const char *cosmos_response_session_token(const struct cosmos_response_t *response);

/**
 * Borrowed pointer to the ETag, or NULL when absent.
 */
const char *cosmos_response_etag(const struct cosmos_response_t *response);

/**
 * Borrowed pointer to the continuation token, or NULL when absent.
 */
const char *cosmos_response_continuation_token(const struct cosmos_response_t *response);

/**
 * Borrowed pointer to the **next-page** continuation token for a feed
 * page produced by [`crate::submit::cosmos_submit_operation`],
 * or NULL when this was the last page / the response did not come from a
 * feed submit.
 *
 * This is the planner-derived token (from
 * `OperationPlan::to_continuation_token()`) and is the correct token to
 * pass back as `CosmosOperationRequest::continuation_token` to fetch the
 * following page ŌĆö including for cross-partition queries. It differs from
 * [`cosmos_response_continuation_token`], which surfaces the raw server
 * header continuation (valid only for trivial single-partition reads).
 *
 * The returned pointer is valid until [`cosmos_response_free`] is called
 * on this response handle.
 */
const char *cosmos_response_next_continuation(const struct cosmos_response_t *response);

/**
 * Zero-copy borrowed view of the response body bytes. NULL pointer +
 * 0 length when the body is empty / response is NULL.
 *
 * For multi-part feed bodies (driver's `ResponseBody::Items`) this
 * returns the **first** part only; full multi-part iteration is a
 * follow-up alongside the feed pagination surface.
 *
 * The returned pointer is valid until [`cosmos_response_free`] is
 * called on this response handle.
 */
int32_t cosmos_response_body(const struct cosmos_response_t *response,
                             const uint8_t **out_data,
                             uintptr_t *out_len);

/**
 * Fills `out_view` with a snapshot of the response's scalar and
 * borrowed-string fields and returns `SUCCESS`. Returns `INVALID_ARGUMENT`
 * (leaving `*out_view` untouched) when `response` or `out_view` is NULL.
 *
 * This is the single-call alternative to `cosmos_response_status_code` +
 * `_request_charge` + `_activity_id` + `_session_token` + `_etag` +
 * `_continuation_token` + `_next_continuation` + `_body`. Every borrowed
 * pointer it returns is valid until [`cosmos_response_free`].
 */
int32_t cosmos_response_view(const struct cosmos_response_t *response,
                             struct cosmos_response_view_t *out_view);

/**
 * Takes ownership of the driver handle stashed inside a degenerate
 * response produced by `cosmos_driver_get_or_create_submit`. Returns
 * NULL on any other response, on NULL input, or after a previous
 * `_take_driver`.
 */
struct cosmos_driver_t *cosmos_response_take_driver(struct cosmos_response_t *response);

/**
 * Takes ownership of the container reference stashed inside a
 * degenerate response produced by
 * `cosmos_driver_resolve_container_submit`. Same semantics as
 * `_take_driver`.
 */
struct cosmos_container_ref_t *cosmos_response_take_container(struct cosmos_response_t *response);

/**
 * Lifecycle: free a `cosmos_runtime_t *` previously returned by the runtime
 * builder.
 *
 * Drops the FFI handle's `Arc` reference. Any completion queues created
 * against this runtime continue to function until their own `Arc` references
 * are dropped, but no new queues can be created from the now-freed handle.
 * NULL is a no-op.
 */
void cosmos_runtime_free(struct cosmos_runtime_t *runtime);

/**
 * Lifecycle: allocate a new `cosmos_runtime_builder_t`.
 *
 * The returned handle must be freed via [`cosmos_runtime_builder_free`] if
 * `cosmos_runtime_builder_build` is never called on it. Successful
 * `_build` consumes the handle.
 */
struct cosmos_runtime_builder_t *cosmos_runtime_builder_new(void);

/**
 * Lifecycle: free a `cosmos_runtime_builder_t *` that was never consumed
 * by [`cosmos_runtime_builder_build`].
 *
 * Calling `_free` on a builder after a successful `_build` is undefined
 * behavior. NULL is a no-op.
 */
void cosmos_runtime_builder_free(struct cosmos_runtime_builder_t *builder);

/**
 * Sets the workload identifier.
 *
 * Valid range: 1ŌĆō50. Out-of-range values return `INVALID_OPTION_VALUE`
 * with no mutation to the builder.
 */
int32_t cosmos_runtime_builder_with_workload_id(struct cosmos_runtime_builder_t *builder,
                                                uint8_t workload_id);

/**
 * Sets the correlation ID for client-side metrics.
 *
 * Constraints: Ōēż50 characters, HTTP-header-safe (alphanumeric, hyphen,
 * underscore, dot, tilde). Strings outside this contract return
 * `INVALID_OPTION_VALUE` with no mutation.
 */
int32_t cosmos_runtime_builder_with_correlation_id(struct cosmos_runtime_builder_t *builder,
                                                   const char *correlation_id);

/**
 * Sets the user-agent suffix.
 *
 * Constraints: Ōēż25 characters, HTTP-header-safe (alphanumeric, hyphen,
 * underscore, dot, tilde). Strings outside this contract return
 * `INVALID_OPTION_VALUE` with no mutation.
 */
int32_t cosmos_runtime_builder_with_user_agent_suffix(struct cosmos_runtime_builder_t *builder,
                                                      const char *suffix);

/**
 * Sets a wrapping-SDK identifier prepended to the User-Agent header.
 *
 * Per the driver contract, the value is sanitized server-side (non-ASCII
 * stripped, whitespace trimmed); empty / whitespace-only is treated as
 * "unset". The FFI does not pre-validate the contents ŌĆö any UTF-8 string
 * is accepted and forwarded to the driver's normalizer.
 */
int32_t cosmos_runtime_builder_with_wrapping_sdk_identifier(struct cosmos_runtime_builder_t *builder,
                                                            const char *identifier);

/**
 * Sets the CPU/memory monitoring refresh interval (milliseconds).
 *
 * Valid range: 1000ŌĆō60000 ms (1ŌĆō60 seconds). Out-of-range values return
 * `INVALID_OPTION_VALUE` with no mutation.
 *
 * The FFI rejects values outside the documented range up-front ŌĆö even
 * though the merged driver does not itself validate, surfacing the
 * constraint here gives external language SDKs an early deterministic
 * error rather than opaque behavior at the first sampling tick.
 */
int32_t cosmos_runtime_builder_with_cpu_refresh_interval_ms(struct cosmos_runtime_builder_t *builder,
                                                            uint64_t interval_ms);

/**
 * Consumes the builder, constructs the underlying
 * [`azure_data_cosmos_driver::driver::CosmosDriverRuntime`], and returns it
 * as a fresh `cosmos_runtime_t *`.
 *
 * # Lifetime
 *
 * `cosmos_runtime_builder_build` **consumes** the builder regardless of
 * success or failure. Callers must NOT call
 * [`cosmos_runtime_builder_free`] on the same pointer afterwards.
 *
 * # Parameters
 *
 * - `builder` ŌĆö the builder to consume. Must be non-NULL.
 * - `out_runtime` ŌĆö on success, receives the new runtime handle. Must be
 *   non-NULL.
 * - `out_error` ŌĆö optional. On `RUNTIME_BUILD_FAILED`, receives a rich
 *   `cosmos_error_t *` describing the driver-side failure. If NULL the
 *   rich error is dropped. The slot is never populated on success.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_runtime` populated.
 * - `INVALID_ARGUMENT` (1) when `builder` or `out_runtime` is NULL. In
 *   the `builder == NULL` case nothing is freed; in the `out_runtime ==
 *   NULL` case the builder is still consumed (the driver-side builder
 *   has been moved out and a fresh runtime would otherwise leak).
 * - `RUNTIME_BUILD_FAILED` (4015) when the underlying
 *   `CosmosDriverRuntimeBuilder::build()` returned an error. `*out_error`
 *   is populated when non-NULL.
 */
int32_t cosmos_runtime_builder_build(struct cosmos_runtime_builder_t *builder,
                                     struct cosmos_runtime_t **out_runtime,
                                     struct cosmos_error_t **out_error);

/**
 * Returns an all-unset [`CosmosRuntimeOptions`] by value. The host mutates the
 * fields it cares about and leaves the rest at their default sentinels.
 */
struct cosmos_runtime_options_t cosmos_runtime_options_default(void);

/**
 * Builds a `cosmos_runtime_t *` from a flat [`CosmosRuntimeOptions`] in a
 * single call ŌĆö the single-call alternative to `cosmos_runtime_builder_new` +
 * the per-field setters + `cosmos_runtime_builder_build`.
 *
 * # Parameters
 *
 * - `options` ŌĆö the flat options. A NULL pointer uses the driver defaults for
 *   every field (equivalent to [`cosmos_runtime_options_default`]).
 * - `out_runtime` ŌĆö on success, receives the new runtime handle. Must be
 *   non-NULL.
 * - `out_error` ŌĆö optional. On `RUNTIME_BUILD_FAILED`, receives a rich
 *   `cosmos_error_t *` describing the driver-side failure. If NULL the rich
 *   error is dropped. Never populated on success.
 *
 * # Returns
 *
 * - `SUCCESS` (0) with `*out_runtime` populated.
 * - `INVALID_ARGUMENT` (1) when `out_runtime` is NULL.
 * - `INVALID_UTF8` (2) when a string field is not valid UTF-8.
 * - `INVALID_OPTION_VALUE` (4014) when a field is outside its documented
 *   range.
 * - `RUNTIME_BUILD_FAILED` (4015) when the underlying build failed;
 *   `*out_error` is populated when non-NULL.
 */
int32_t cosmos_runtime_build(const struct cosmos_runtime_options_t *options,
                             struct cosmos_runtime_t **out_runtime,
                             struct cosmos_error_t **out_error);

/**
 * Submits a feed-capable operation for asynchronous execution, binding to
 * the driver's planner so a single page is produced per call.
 *
 * Unlike [`cosmos_submit_singleton_operation`], this path
 * runs `plan_operation` + `execute_plan` internally so it can both
 * **resume** from an inbound continuation token
 * ([`CosmosOperationRequest::continuation_token`]) and **surface** the
 * next-page token via [`crate::response::cosmos_response_next_continuation`].
 *
 * Use this for any operation that can return multiple pages ŌĆö queries,
 * read-all-items, change feed ŌĆö and drive pagination by re-submitting with
 * the returned next token until the completion delivers an end-of-stream
 * response (status code `0`, NULL next token; see the `Ok(None)` contract
 * below).
 *
 * # Completion outcomes
 *
 * - **A page of results**: outcome `OK`; the response carries the body,
 *   headers, and (when more pages remain) a non-NULL next continuation.
 * - **Feed exhausted** (`Ok(None)` from the driver): outcome `OK` with a
 *   degenerate response ŌĆö status code `0`, empty body, NULL next token.
 *   Hosts treat this as end-of-stream.
 * - **Failure**: outcome `ERROR` with the coarse code (+ rich error when
 *   the queue opted in).
 *
 * # Parameters
 *
 * - `driver` ŌĆö non-NULL driver handle.
 * - `request` ŌĆö non-NULL [`CosmosOperationRequest`] describing the
 *   operation. All borrowed pointers must remain valid for the duration of
 *   this call (the wrapper copies everything it needs before returning).
 * - `queue` ŌĆö non-NULL completion queue.
 * - `user_data` ŌĆö opaque, pointer-sized integer cookie (`intptr_t`)
 *   round-tripped verbatim onto the completion; never dereferenced.
 * - `out_pre_error` ŌĆö receives the coarse code on pre-flight failure
 *   (returns NULL). NULL is accepted.
 *
 * # Returns
 *
 * A fresh `cosmos_operation_handle_t *` on success, or NULL on pre-flight
 * failure (with `*out_pre_error` populated when non-NULL). Pre-flight
 * failures include malformed requests (`INVALID_ARGUMENT`), invalid option
 * values (`INVALID_OPTION_VALUE`), and the queue states
 * (`QUEUE_SHUTDOWN` / `QUEUE_FULL`).
 */
struct cosmos_operation_handle_t *cosmos_submit_operation(const struct cosmos_driver_t *driver,
                                                          const struct cosmos_operation_request_t *request,
                                                          struct cosmos_cq_t *queue,
                                                          intptr_t user_data,
                                                          cosmos_error_code_t *out_pre_error);

/**
 * Submits a singleton (single-result) operation for asynchronous
 * execution, binding to [`CosmosDriver::execute_singleton_operation`].
 *
 * Use this for point operations and any operation that returns exactly one
 * result ŌĆö create / read / replace / delete / patch item, database and
 * container CRUD, read/replace offer. Feed kinds (queries, read-all,
 * change feed) must go through
 * [`cosmos_submit_operation`] instead; submitting one here
 * makes the driver assert in debug builds and yields a
 * `CLIENT_SINGLETON_OPERATION_RETURNED_EMPTY_PAGE`-shaped error in release.
 *
 * The inbound [`CosmosOperationRequest::continuation_token`] is ignored on
 * this path (singletons do not paginate).
 *
 * # Parameters / Returns
 *
 * Identical in shape to [`cosmos_submit_operation`]; the
 * completion always carries a single response (outcome `OK`) or an error
 * (outcome `ERROR`).
 */
struct cosmos_operation_handle_t *cosmos_submit_singleton_operation(const struct cosmos_driver_t *driver,
                                                                    const struct cosmos_operation_request_t *request,
                                                                    struct cosmos_cq_t *queue,
                                                                    intptr_t user_data,
                                                                    cosmos_error_code_t *out_pre_error);

/**
 * Asynchronous variant of [`crate::driver::cosmos_driver_get_or_create_blocking`].
 *
 * Bridges `CosmosDriverRuntime::get_or_create_driver` through the
 * submit pipeline; the completion delivers a degenerate
 * `cosmos_response_t` from which
 * [`crate::response::cosmos_response_take_driver`] extracts the new
 * driver handle.
 */
struct cosmos_operation_handle_t *cosmos_driver_get_or_create_submit(const struct cosmos_runtime_t *runtime,
                                                                     const struct cosmos_account_ref_t *account,
                                                                     const struct cosmos_driver_options_t *options,
                                                                     struct cosmos_cq_t *queue,
                                                                     intptr_t user_data,
                                                                     cosmos_error_code_t *out_pre_error);

/**
 * Asynchronous variant of
 * [`crate::container_ref::cosmos_driver_resolve_container_blocking`].
 *
 * Same shape as the get-or-create variant ŌĆö the completion delivers a
 * degenerate response from which
 * [`crate::response::cosmos_response_take_container`] extracts the
 * resolved container handle.
 */
struct cosmos_operation_handle_t *cosmos_driver_resolve_container_submit(const struct cosmos_driver_t *driver,
                                                                         const char *database_id,
                                                                         const char *container_id,
                                                                         struct cosmos_cq_t *queue,
                                                                         intptr_t user_data,
                                                                         cosmos_error_code_t *out_pre_error);

